import type { Blob } from '@google/genai';

export const AUDIO_INPUT_SAMPLE_RATE = 16000;
export const AUDIO_OUTPUT_SAMPLE_RATE = 24000;

/**
 * Converts a base64 string to a Uint8Array.
 */
function base64ToBytes(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

/**
 * Converts a Uint8Array to a base64 string.
 */
function bytesToBase64(bytes: Uint8Array): string {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

/**
 * Decodes raw PCM audio data (Int16) from the API into an AudioBuffer.
 */
export async function decodeAudioData(
  base64Data: string,
  ctx: AudioContext,
): Promise<AudioBuffer> {
  const bytes = base64ToBytes(base64Data);
  const dataInt16 = new Int16Array(bytes.buffer);

  // Create buffer: 1 channel, length matching data, API output rate (24k)
  const buffer = ctx.createBuffer(1, dataInt16.length, AUDIO_OUTPUT_SAMPLE_RATE);
  const channelData = buffer.getChannelData(0);

  // Convert Int16 to Float32
  for (let i = 0; i < dataInt16.length; i++) {
    channelData[i] = dataInt16[i] / 32768.0;
  }

  return buffer;
}

/**
 * Encodes raw PCM audio data (Float32 from Mic) into the format expected by the API (base64 wrapped).
 */
export function createAudioBlob(inputData: Float32Array): Blob {
  const l = inputData.length;
  const int16 = new Int16Array(l);

  // Downsample/Convert Float32 (-1.0 to 1.0) to Int16 (-32768 to 32767)
  for (let i = 0; i < l; i++) {
    const s = Math.max(-1, Math.min(1, inputData[i]));
    int16[i] = s < 0 ? s * 0x8000 : s * 0x7FFF;
  }

  return {
    data: bytesToBase64(new Uint8Array(int16.buffer)),
    mimeType: `audio/pcm;rate=${AUDIO_INPUT_SAMPLE_RATE}`,
  };
}

import React, { useState, useRef, useEffect } from 'react';
import { LeadNotification } from './components/LeadNotification';
import { CallOverlay } from './components/CallOverlay';
import { CallFloatingButton } from './components/CallFloatingButton';
import { ChatOverlay } from './components/ChatOverlay';
import { Lead, LeadToolArgs } from './types';
import { SYSTEM_INSTRUCTION, CREATE_LEAD_TOOL, CHECK_STATUS_TOOL, NAVIGATE_WEBSITE_TOOL, SEND_WHATSAPP_TOOL } from './constants';
import { createAudioBlob, decodeAudioData, AUDIO_INPUT_SAMPLE_RATE, AUDIO_OUTPUT_SAMPLE_RATE } from './services/audioUtils';
import { saveLeadToSupabase, checkStatusInSupabase } from './services/supabaseService';
import { sendWhatsAppMessage } from './services/messagingService';
import { GoogleGenAI, LiveServerMessage, Modality } from "@google/genai";

type AppMode = 'idle' | 'call' | 'chat';

function App() {
  const [mode, setMode] = useState<AppMode>('idle');
  const [isCallConnected, setIsCallConnected] = useState(false); // NEW STATE: Tracks if socket is open
  const [newLead, setNewLead] = useState<Lead | null>(null);
  const [volumeLevel, setVolumeLevel] = useState(0);
  const [errorMessage, setErrorMessage] = useState<string | null>(null);

  const sessionRef = useRef<any>(null);
  const inputAudioContextRef = useRef<AudioContext | null>(null);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const mediaStreamRef = useRef<MediaStream | null>(null);
  const scriptProcessorRef = useRef<ScriptProcessorNode | null>(null);
  const audioSourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const nextStartTimeRef = useRef<number>(0);

  // Data Tracking Refs
  const transcriptRef = useRef<string>("");
  const currentLeadDataRef = useRef<Partial<LeadToolArgs>>({});

  // Notify parent (Hostinger) to resize based on view mode
  useEffect(() => {
     window.parent.postMessage({ type: 'resize-widget', view: 'full' }, '*');
  }, [mode]);

  const stopCall = async () => {
    // 1. Perform Safety Save
    if (currentLeadDataRef.current.contactInfo) {
      const finalLead: LeadToolArgs = {
        customerName: currentLeadDataRef.current.customerName || "Anonymous Caller",
        contactInfo: currentLeadDataRef.current.contactInfo || "Not Provided",
        interest: currentLeadDataRef.current.interest || "General Inquiry",
        language: currentLeadDataRef.current.language || "en",
        summary: `[AI SUMMARY]\n${currentLeadDataRef.current.summary || "No AI summary generated."}`,
        city: currentLeadDataRef.current.city,
        experience: currentLeadDataRef.current.experience,
        passportStatus: currentLeadDataRef.current.passportStatus,
        age: currentLeadDataRef.current.age,
        remarks: currentLeadDataRef.current.remarks || "Call ended.",
        bestCallTime: currentLeadDataRef.current.bestCallTime
      };
      saveLeadToSupabase(finalLead);
    }

    // 2. Cleanup Audio
    if (mediaStreamRef.current) {
      mediaStreamRef.current.getTracks().forEach(track => track.stop());
      mediaStreamRef.current = null;
    }
    if (scriptProcessorRef.current) {
      scriptProcessorRef.current.disconnect();
      scriptProcessorRef.current = null;
    }
    if (inputAudioContextRef.current) {
      inputAudioContextRef.current.close();
      inputAudioContextRef.current = null;
    }
    audioSourcesRef.current.forEach(source => source.stop());
    audioSourcesRef.current.clear();
    if (outputAudioContextRef.current) {
      outputAudioContextRef.current.close();
      outputAudioContextRef.current = null;
    }
    sessionRef.current = null;

    // 3. Reset State
    setIsCallConnected(false);
    setMode('idle');
    setVolumeLevel(0);
    nextStartTimeRef.current = 0;
    transcriptRef.current = "";
    currentLeadDataRef.current = {};
  };

  const startCall = async () => {
    setErrorMessage(null);
    const apiKey = process.env.API_KEY;
    if (!apiKey) {
      setErrorMessage("API Key is missing.");
      return;
    }

    setMode('call');
    setIsCallConnected(false); // Start in "Calling..." state

    try {
      inputAudioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: AUDIO_INPUT_SAMPLE_RATE });
      outputAudioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: AUDIO_OUTPUT_SAMPLE_RATE });

      if (outputAudioContextRef.current.state === 'suspended') {
          await outputAudioContextRef.current.resume();
      }

      let stream: MediaStream;
      try {
        stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      } catch (micErr) {
        console.error("Mic Error:", micErr);
        setErrorMessage("Microphone access denied.");
        setMode('idle');
        return;
      }

      mediaStreamRef.current = stream;

      const ai = new GoogleGenAI({ apiKey });

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-09-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          systemInstruction: SYSTEM_INSTRUCTION,
          tools: [
            { functionDeclarations: [CREATE_LEAD_TOOL, CHECK_STATUS_TOOL, NAVIGATE_WEBSITE_TOOL, SEND_WHATSAPP_TOOL] }
          ],
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Aoede' } }
          }
        },
        callbacks: {
            onopen: () => {
                console.log("Connection Established");
                setErrorMessage(null);

                // IMPORTANT: Set connected state ONLY when socket is open
                setIsCallConnected(true);

                if (!inputAudioContextRef.current) return;
                const source = inputAudioContextRef.current.createMediaStreamSource(stream);
                const processor = inputAudioContextRef.current.createScriptProcessor(4096, 1, 1);
                scriptProcessorRef.current = processor;

                processor.onaudioprocess = (e) => {
                    const inputData = e.inputBuffer.getChannelData(0);
                    let sum = 0;
                    for(let i = 0; i < inputData.length; i++) sum += inputData[i] * inputData[i];
                    const rms = Math.sqrt(sum / inputData.length);
                    setVolumeLevel(Math.min(rms * 5, 1));

                    // Optimization: Lower threshold slightly for smoother VAD
                    if (rms > 0.001) { 
                        const pcmBlob = createAudioBlob(inputData);
                        sessionPromise.then(session => {
                            session.sendRealtimeInput({ media: pcmBlob });
                        }).catch(e => console.error("Send Error:", e));
                    }
                };

                setTimeout(() => {
                    source.connect(processor);
                    processor.connect(inputAudioContextRef.current!.destination);

                    // FORCE NEHA TO SPEAK FIRST
                    // Sending a dummy update prompts the model to generate the greeting defined in System Instruction
                    sessionPromise.then(session => {
                        session.sendRealtimeInput({
                            media: {
                                mimeType: "audio/pcm;rate=16000",
                                data: ""
                            }
                        });
                    });
                }, 500);
            },
            onmessage: async (message: LiveServerMessage) => {
                const base64Audio = message.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
                if (base64Audio && outputAudioContextRef.current) {
                    const ctx = outputAudioContextRef.current;
                    nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);
                    const audioBuffer = await decodeAudioData(base64Audio, ctx);
                    const source = ctx.createBufferSource();
                    source.buffer = audioBuffer;
                    source.connect(ctx.destination);
                    source.addEventListener('ended', () => {
                        audioSourcesRef.current.delete(source);
                    });
                    source.start(nextStartTimeRef.current);
                    nextStartTimeRef.current += audioBuffer.duration;
                    audioSourcesRef.current.add(source);
                }

                if (message.serverContent?.interrupted) {
                    audioSourcesRef.current.forEach(src => src.stop());
                    audioSourcesRef.current.clear();
                    nextStartTimeRef.current = 0;
                }

                if (message.toolCall) {
                    for (const fc of message.toolCall.functionCalls) {
